import{_ as o,o as r,c as e,a3 as a}from"./chunks/framework.BTFg6ESq.js";const g=JSON.parse('{"title":"代码格式化","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/code-formatter.md","filePath":"user-guide/tools/code-formatter.md","lastUpdated":1778221347000}'),l={name:"user-guide/tools/code-formatter.md"};function d(i,t,n,s,c,p){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="代码格式化" tabindex="-1">代码格式化 <a class="header-anchor" href="#代码格式化" aria-label="Permalink to &quot;代码格式化&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>代码格式化工具是一个基于 Prettier 引擎的多语言代码格式化工具，支持 9 种主流编程和标记语言。当你从不同来源复制来一段乱糟糟的代码时，它能一键整理为规范格式；当你需要在不同项目间统一代码风格时，它也能帮上忙。它最大的特色是<strong>多语言覆盖广</strong>——从前端到后端，从配置到文档，一把搞定。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>多语言支持</strong>：覆盖 JavaScript、TypeScript、JSON、HTML、CSS、Markdown、PHP、XML、YAML 共 9 种语言，一个工具解决所有格式化需求</li><li><strong>实时格式化</strong>：输入代码即自动格式化，500ms 智能防抖，避免高频重排</li><li><strong>一键复制与发送</strong>：格式化结果一键复制到剪贴板，或直接发送到 AI 聊天会话</li><li><strong>报错零崩溃</strong>：即使代码有语法错误或插件加载失败，也会显示友好提示并展示原始代码，不会让工具白屏</li><li><strong>按需加载</strong>：常用语言（JS/TS/HTML/CSS/Markdown）即开即用，非常用语言（PHP/XML）首次使用时才自动加载插件</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="首次使用-5-步走" tabindex="-1">首次使用 5 步走 <a class="header-anchor" href="#首次使用-5-步走" aria-label="Permalink to &quot;首次使用 5 步走&quot;">​</a></h3><p><strong>第一步：打开工具</strong></p><p>在左侧工具列表中找到 <strong>代码格式化</strong>，点击进入。你会看到一个&quot;左输入 + 右输出&quot;的双面板界面，左上角有一个语言选择下拉框。</p><blockquote><p>TODO: 截图 - 工具整体界面，标注输入面板、输出面板和语言选择器</p></blockquote><p><strong>第二步：选择语言</strong></p><p>在左上角的语言选择下拉框中，选择你要格式化的代码语言。语言按分组排列：</p><table tabindex="0"><thead><tr><th>分组</th><th>语言</th></tr></thead><tbody><tr><td>前端语言</td><td>JavaScript、TypeScript、JSON、HTML、CSS</td></tr><tr><td>后端语言</td><td>PHP</td></tr><tr><td>配置/数据</td><td>XML、YAML</td></tr><tr><td>标记语言</td><td>Markdown</td></tr></tbody></table><p>下拉框支持<strong>过滤搜索</strong>——输入关键字（如&quot;type&quot;）即可快速定位到 TypeScript。</p><blockquote><p>TODO: 截图 - 语言选择下拉框展开，标注分组和搜索框</p></blockquote><p><strong>第三步：输入代码</strong></p><p>点击左侧输入面板，直接键入或粘贴（<kbd>Ctrl</kbd> + <kbd>V</kbd>）你的代码。输入后工具会<strong>自动</strong>在 500ms 内完成格式化，右侧输出面板会实时展示结果。</p><blockquote><p>TODO: 截图 - 左侧输入面板粘贴代码，右侧输出面板展示格式化结果</p></blockquote><p><strong>第四步：检查结果</strong></p><p>格式化完成后，观察右侧输出面板：</p><ul><li><strong>格式化成功</strong>：代码已按规范整理好缩进、引号、逗号等</li><li><strong>格式化失败</strong>：底部会出现红色错误提示，说明具体错误原因，同时输出面板会显示原始代码（不会丢失内容）</li></ul><blockquote><p>TODO: 截图 - 格式化失败时的红色错误提示</p></blockquote><p><strong>第五步：使用结果</strong></p><p>右侧输出面板中的格式化代码，你可以：</p><ul><li><strong>复制</strong>：点击右侧面板标题栏的 <strong>复制</strong> 按钮，一键复制到剪贴板</li><li><strong>发送到聊天</strong>：点击 <strong>发送到聊天</strong>，结果直接进入 AI 聊天会话</li><li><strong>切换语言重试</strong>：如果结果不理想，可以换一种语言试试</li></ul><blockquote><p>TODO: 截图 - 标注复制和发送到聊天按钮</p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="界面布局" tabindex="-1">界面布局 <a class="header-anchor" href="#界面布局" aria-label="Permalink to &quot;界面布局&quot;">​</a></h3><p>工具采用经典的双栏对比布局，左右两栏各被 <code>InfoCard</code> 组件包裹，保持与系统主题风格一致。</p><h4 id="左栏-输入代码" tabindex="-1">左栏：输入代码 <a class="header-anchor" href="#左栏-输入代码" aria-label="Permalink to &quot;左栏：输入代码&quot;">​</a></h4><p>左侧面板用于输入原始代码，包含：</p><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td><strong>标题栏</strong></td><td>显示&quot;输入代码&quot;和语言选择下拉框</td></tr><tr><td><strong>代码输入区</strong></td><td>可编辑的大文本输入框，支持任意文本粘贴</td></tr></tbody></table><p>语言选择是一个 <code>el-select</code> 组件，支持：</p><ul><li><strong>分组展示</strong>：按语言用途分为四个组，视觉上清晰明了</li><li><strong>过滤搜索</strong>：点击后输入文字可快速筛选语言</li></ul><h4 id="右栏-输出代码" tabindex="-1">右栏：输出代码 <a class="header-anchor" href="#右栏-输出代码" aria-label="Permalink to &quot;右栏：输出代码&quot;">​</a></h4><p>右侧面板展示格式化后的结果，包含：</p><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td><strong>标题栏</strong></td><td>显示&quot;输出代码&quot;和操作按钮（复制、发送到聊天）</td></tr><tr><td><strong>代码输出区</strong></td><td>只读的大文本展示区，格式化结果在此显示</td></tr><tr><td><strong>错误提示</strong></td><td>底部区域，格式失败时显示红色错误信息</td></tr></tbody></table><p>右侧面板是<strong>只读</strong>的，不可编辑。你可以在标题栏执行两个操作：</p><ul><li><strong>复制</strong>：将格式化结果写入系统剪贴板，成功后会提示&quot;格式化后的代码已复制到剪贴板！&quot;</li><li><strong>发送到聊天</strong>：将格式化后的代码发送到 AI 聊天会话，方便后续基于它继续讨论</li></ul><blockquote><p>TODO: 截图 - 右侧面板标题栏，标注复制和发送到聊天按钮</p></blockquote><h3 id="语言支持详情" tabindex="-1">语言支持详情 <a class="header-anchor" href="#语言支持详情" aria-label="Permalink to &quot;语言支持详情&quot;">​</a></h3><p>每种语言对应不同的 Prettier 解析器和预设配置：</p><table tabindex="0"><thead><tr><th>语言</th><th>解析器</th><th>备注</th></tr></thead><tbody><tr><td>JavaScript</td><td><code>babel</code></td><td>默认语言</td></tr><tr><td>TypeScript</td><td><code>typescript</code></td><td></td></tr><tr><td>JSON</td><td><code>json</code></td><td></td></tr><tr><td>HTML</td><td><code>html</code></td><td></td></tr><tr><td>CSS</td><td><code>css</code></td><td></td></tr><tr><td>Markdown</td><td><code>markdown</code></td><td></td></tr><tr><td>PHP</td><td><code>php</code></td><td>首次使用时动态加载 <code>@prettier/plugin-php</code></td></tr><tr><td>XML</td><td><code>xml</code></td><td>首次使用时动态加载 <code>@prettier/plugin-xml</code>，启用 <code>xmlWhitespaceSensitivity: &#39;ignore&#39;</code></td></tr><tr><td>YAML</td><td><code>yaml</code></td><td></td></tr></tbody></table><blockquote><div class="tip custom-block"><p class="custom-block-title">关于 PHP 和 XML</p><p>这两个语言的格式化插件采用<strong>动态加载</strong>策略。首次使用时页面可能会短暂卡顿（等待插件下载），后续使用则不会有此延迟。如果插件加载失败（如网络问题或版本不兼容），工具会给出明确提示，不影响其他语言的使用。</p></div></blockquote><h3 id="格式化引擎规则" tabindex="-1">格式化引擎规则 <a class="header-anchor" href="#格式化引擎规则" aria-label="Permalink to &quot;格式化引擎规则&quot;">​</a></h3><p>工具使用 Prettier 引擎的默认配置，默认启用以下风格规则：</p><ul><li><strong>单引号</strong>（<code>singleQuote: true</code>）</li><li><strong>尾随逗号</strong>（<code>trailingComma: &#39;es5&#39;</code>）</li></ul><p>这些规则保证了输出的一致性和业界主流风格。</p><h3 id="实时格式化机制" tabindex="-1">实时格式化机制 <a class="header-anchor" href="#实时格式化机制" aria-label="Permalink to &quot;实时格式化机制&quot;">​</a></h3><p>代码输入采用 <strong>500ms 防抖</strong> 机制——你连续输入时不会立即触发格式化，而是等你停止输入 500ms 后才执行。这样做有两个好处：</p><ol><li><strong>避免卡顿</strong>：不会在你快速打字或粘贴大量代码时频繁触发格式化，导致界面卡顿</li><li><strong>即时反馈</strong>：停止输入后半秒内即可看到结果，感知上是即时的</li></ol><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="与-ai-聊天联动" tabindex="-1">与 AI 聊天联动 <a class="header-anchor" href="#与-ai-聊天联动" aria-label="Permalink to &quot;与 AI 聊天联动&quot;">​</a></h3><p>格式化后的代码可以通过 <strong>发送到聊天</strong> 按钮直接传入 AI 聊天会话。典型的联动场景：</p><ol><li>从 GitHub Gist 或 Stack Overflow 复制一段乱格式的代码</li><li>在代码格式化工具中整理好缩进和风格</li><li>点击 <strong>发送到聊天</strong> 将格式化后的代码传给 AI</li><li>在聊天中进一步提问：&quot;帮我优化这段代码&quot; 或 &quot;解释这个函数的作用&quot;</li></ol><blockquote><p>TODO: 截图 - 发送到聊天后的 AI 会话界面</p></blockquote><h3 id="多语言切换调试" tabindex="-1">多语言切换调试 <a class="header-anchor" href="#多语言切换调试" aria-label="Permalink to &quot;多语言切换调试&quot;">​</a></h3><p>当不确定一段代码该用什么语言解析时，可以：</p><ol><li>在左侧粘贴代码</li><li>从下拉框中选择一种语言查看格式化效果</li><li>如果效果不对（比如把 Markdown 选成了 HTML），切换到其他语言重试</li><li>通过对比不同解析器下的输出，找到最合适的语言选项</li></ol><p>技巧：如果一段代码同时包含多种语言（如 Vue SFC 中的 <code>&lt;template&gt;</code> + <code>&lt;script&gt;</code>），建议将各个部分分别复制出来，分别用 HTML 和 JavaScript 处理。</p><h3 id="与复制操作配合的工作流" tabindex="-1">与复制操作配合的工作流 <a class="header-anchor" href="#与复制操作配合的工作流" aria-label="Permalink to &quot;与复制操作配合的工作流&quot;">​</a></h3><p>对于需要频繁格式化代码的日常场景，推荐以下工作流：</p><ol><li><strong>在浏览器/编辑器中</strong> 选择代码并复制（<kbd>Ctrl</kbd> + <kbd>C</kbd>）</li><li><strong>切换到 AIO Hub</strong> 在输入面板粘贴（<kbd>Ctrl</kbd> + <kbd>V</kbd>）——自动格式化</li><li><strong>确认结果无误</strong> 后点击 <strong>复制</strong>（<kbd>Ctrl</kbd> + 点击）——格式化好的代码回到剪贴板</li><li><strong>回到原处</strong> 粘贴使用</li></ol><p>整个过程不超过 10 秒，比手动调整缩进和引号快得多。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-为什么格式化后代码风格和我预期的不一样" tabindex="-1">Q：为什么格式化后代码风格和我预期的不一样？ <a class="header-anchor" href="#q-为什么格式化后代码风格和我预期的不一样" aria-label="Permalink to &quot;Q：为什么格式化后代码风格和我预期的不一样？&quot;">​</a></h3><p>代码格式化工具使用 Prettier engine 的默认配置（单引号、ES5 尾随逗号等），这是业界最广泛采用的风格之一。如果你的项目有特定代码规范（如双引号、无尾随逗号），预置的风格可能不能完全匹配。你可以先在工具中格式化，再根据项目规范做少量手动调整。</p><p>另外，确保你选择了正确的语言——比如把 TypeScript 代码选成 JavaScript，有时会导致解析差异。</p><h3 id="q-粘贴代码后没有自动格式化" tabindex="-1">Q：粘贴代码后没有自动格式化？ <a class="header-anchor" href="#q-粘贴代码后没有自动格式化" aria-label="Permalink to &quot;Q：粘贴代码后没有自动格式化？&quot;">​</a></h3><p>检查以下几点：</p><ul><li><strong>确认输入面板有内容</strong>：完全为空时不会触发格式化（右侧会保持空白）</li><li><strong>确认语言选择正确</strong>：如果选择了与代码不匹配的语言，Prettier 可能解析失败</li><li><strong>查看底部错误提示</strong>：如果有红色文本，说明格式化失败。常见原因包括语法错误（如缺少括号、分号）、不完整的代码片段等</li></ul><p>如果所有检查都正常仍无反应，可以尝试切换一下语言再切回来，触发一次重新格式化。</p><h3 id="q-php-或-xml-提示-插件加载失败" tabindex="-1">Q：PHP 或 XML 提示&quot;插件加载失败&quot;？ <a class="header-anchor" href="#q-php-或-xml-提示-插件加载失败" aria-label="Permalink to &quot;Q：PHP 或 XML 提示&quot;插件加载失败&quot;？&quot;">​</a></h3><p>PHP 和 XML 的格式化插件是动态加载的，首次使用需要联网下载。如果网络环境受限或插件版本不兼容，可能会出现加载失败提示。</p><p>解决办法：</p><ul><li><strong>检查网络连接</strong>：确保可以正常访问 npm registry</li><li><strong>重试</strong>：退出工具重新进入，会再次尝试加载</li><li><strong>使用备选方案</strong>：PHP 代码可以使用你习惯的 IDE 格式化，XML 可以先用 JSON 格式处理（如果数据是 JSON 格式误选了 XML）</li></ul><p>PHP 插件依赖 <code>@prettier/plugin-php</code>，XML 插件依赖 <code>@prettier/plugin-xml</code>，两者都是社区维护的 Prettier 插件。</p><h3 id="q-支持-vue-或-react-的-jsx-tsx-吗" tabindex="-1">Q：支持 Vue 或 React 的 JSX/TSX 吗？ <a class="header-anchor" href="#q-支持-vue-或-react-的-jsx-tsx-吗" aria-label="Permalink to &quot;Q：支持 Vue 或 React 的 JSX/TSX 吗？&quot;">​</a></h3><p>目前支持的语言列表中不包含 Vue SFC（<code>.vue</code>）或 JSX/TSX 语法。建议的处理方式：</p><ul><li><strong>Vue 文件</strong>：将 <code>&lt;template&gt;</code> 部分复制出来用 HTML 格式化，<code>&lt;script&gt;</code> 部分用 JavaScript/TypeScript</li><li><strong>JSX/TSX</strong>：用 TypeScript 解析器处理 script 部分，通常能正确处理 JSX 语法</li></ul><p>未来的版本会考虑扩展对更多语言的支持。</p><h3 id="q-格式化结果可以复制但为什么不能编辑输出内容" tabindex="-1">Q：格式化结果可以复制但为什么不能编辑输出内容？ <a class="header-anchor" href="#q-格式化结果可以复制但为什么不能编辑输出内容" aria-label="Permalink to &quot;Q：格式化结果可以复制但为什么不能编辑输出内容？&quot;">​</a></h3><p>右侧输出面板是<strong>只读</strong>的，这是有意设计——它展示的是格式化结果，保证你看到的内容不会被意外修改。如果你需要对输出内容进一步修改：</p><ol><li>从输出面板 <strong>复制</strong> 结果</li><li>粘贴到输入面板（这会覆盖原有输入，触发重新格式化）</li><li>在输入面板中手动调整</li><li>等待自动格式化后观察结果</li></ol><p>或者，点击 <strong>发送到聊天</strong> 后在 AI 聊天中继续编辑。</p>',85)])])}const u=o(l,[["render",d]]);export{g as __pageData,u as default};
